void main() {
  int a = 10, b = 3;
  print(a + b);   // 13
  print(a - b);   // 7
  print(a * b);   // 30
  print(a / b);   // 3.3333333333333335 (double)
  print(a ~/ b);  // 3 (integer division)
  print(a % b);   // 1 (remainder)
}

void main() {
  int x = 5, y = 8;
  print(x == y); // false
  print(x != y); // true
  print(x > y);  // false
  print(x < y);  // true
  print(x >= 5); // true
  print(y <= 8); // true
}

void main() {
  var value = 'Hello';
  print(value is String);   // true
  print(value is int);      // false
  print(value is! bool);    // true
}

void main() {
  bool sunny = true, warm = false;
  print(sunny && warm); // false
  print(sunny || warm); // true
  print(!sunny);        // false
}

void main() {
  int a = 10;
  a += 5;  // a = a + 5 -> 15
  print(a);
  a ~/= 2; // a = a ~/ 2 -> 7
  print(a);
}

void main() {
  int age = 18;
  String status = (age >= 18) ? 'Adult' : 'Minor';
  print(status); // Adult
}

class Person {
  String name = '';
  int age = 0;
  void sayHello() => print('Hi, I am $name');
}

void main() {
  Person person = Person()
    ..name = 'Alice'
    ..age = 30
    ..sayHello();
}

void main() {
  String? name;
  print(name?.length);   // null (safe access)

  String displayName = name ?? 'Guest';
  print(displayName);    // Guest

  name ??= 'Alice';
  print(name);           // Alice (assigned because it was null)
}

void main() {
  int result = 5 + 3 * 2;   // 5 + (3 * 2) = 11
  print(result);
  result = (5 + 3) * 2;     // (5 + 3) * 2 = 16
  print(result);
}

void main() {
  // Mixing various operators
  int a = 15, b = 4;
  double c = 10.5;

  // Arithmetic + relational + logical
  if ((a ~/ b > 3) && (c > 10)) {
    print('Condition met');
  }

  // Ternary + assignment
  int min = (a < b) ? a : b;
  print('Minimum: $min');

  // Cascade on a list
  var numbers = [1, 2, 3]
    ..add(4)
    ..removeAt(0);
  print(numbers); // [2, 3, 4]
}

